import React, { useEffect } from "react";
import "./Home.css";
import { MdLocalPhone } from "react-icons/md";
import Aos from "aos";
import "aos/dist/aos.css";

function Home() {
  useEffect(() => {
    Aos.init({ duration: 2000 });
  }, []);

  function scrollToElement() {
    const targetElement = document.getElementById("main");
    if (targetElement) {
      targetElement.scrollIntoView({ behavior: "smooth" });
    }
  }
  return (
    <div>
      <section id="home" className="home">
        <div className="overlay"></div>
        <img
          data-aos="fade-down"
          src="/images/ch1.jpg"
          alt="wallpaper"
          className="imgWallpaper"
        ></img>

        <div className="homeContent container">
          <div className="textDiv">
            <span data-aos="fade-down" className="smallText">
              Live Your Dream
            </span>
            <h1 data-aos="fade-up" className="homeTitle">
              In Search Of Incredible
            </h1>
          </div>

          <div data-aos="zoom-in-right" className="homeFooterIcons flex">
            <div className="rightIcons">
              <MdLocalPhone className="icon" />
              <p className="number">+96333448412</p>
            </div>
            <div className="rightIcons">
              <MdLocalPhone className="icon" />
              <p className="number">+96333448412</p>
            </div>
          </div>
        </div>
        <div className="scrollDown" onClick={scrollToElement}>
          <span></span>
          <span></span>
          <span></span>
        </div>
      </section>
    </div>
  );
}

export default Home;
